import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2016年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2016年/核心总结.md","filePath":"01_letters/2016年/核心总结.md"}'),t={name:"01_letters/2016年/核心总结.md"};function o(h,a,u,n,d,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="_2016年巴菲特致股东信核心总结" tabindex="-1">2016年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2016年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2016年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长10.7%，股价上涨23.4%</li><li>标普500上涨12.0%</li><li>52年复合年增长率：账面价值19.0%，股价20.8%</li><li>净资产增长275亿美元</li></ul><h2 id="股票回购政策" tabindex="-1">股票回购政策 <a class="header-anchor" href="#股票回购政策" aria-label="Permalink to &quot;股票回购政策&quot;">​</a></h2><h3 id="评估回购的复杂性" tabindex="-1">评估回购的复杂性 <a class="header-anchor" href="#评估回购的复杂性" aria-label="Permalink to &quot;评估回购的复杂性&quot;">​</a></h3><ul><li>对退出股东：回购总是好事（多一个买家）</li><li>对继续持股股东：取决于购买价格</li><li>低于内在价值回购：立即增加每股价值</li><li>高于内在价值回购：伤害继续持股股东</li></ul><h3 id="伯克希尔的政策" tabindex="-1">伯克希尔的政策 <a class="header-anchor" href="#伯克希尔的政策" aria-label="Permalink to &quot;伯克希尔的政策&quot;">​</a></h3><ul><li>授权在账面价值120%或以下回购</li><li>不会&quot;支撑&quot;股价</li><li>回购价格对继续持股和退出股东都有利</li></ul><h2 id="股息政策深度分析" tabindex="-1">股息政策深度分析 <a class="header-anchor" href="#股息政策深度分析" aria-label="Permalink to &quot;股息政策深度分析&quot;">​</a></h2><h3 id="盈利分配的四种方式" tabindex="-1">盈利分配的四种方式 <a class="header-anchor" href="#盈利分配的四种方式" aria-label="Permalink to &quot;盈利分配的四种方式&quot;">​</a></h3><ol><li>再投资现有业务</li><li>收购相关业务</li><li>支付股息</li><li>股票回购</li></ol><h3 id="伯克希尔的股息逻辑" tabindex="-1">伯克希尔的股息逻辑 <a class="header-anchor" href="#伯克希尔的股息逻辑" aria-label="Permalink to &quot;伯克希尔的股息逻辑&quot;">​</a></h3><ul><li>过去52年从不支付股息</li><li>留存收益创造了巨大价值</li><li>股东可自行决定是否&quot;创造股息&quot;</li><li>1美元留存收益 → 超过1美元市场价值</li></ul><h3 id="股息的税收劣势" tabindex="-1">股息的税收劣势 <a class="header-anchor" href="#股息的税收劣势" aria-label="Permalink to &quot;股息的税收劣势&quot;">​</a></h3><ul><li>股息立即征税</li><li>资本利得可递延</li><li>自制股息（卖出股票）更灵活</li></ul><h2 id="重大收购完成" tabindex="-1">重大收购完成 <a class="header-anchor" href="#重大收购完成" aria-label="Permalink to &quot;重大收购完成&quot;">​</a></h2><h3 id="精密铸件公司-precision-castparts" tabindex="-1">精密铸件公司（Precision Castparts） <a class="header-anchor" href="#精密铸件公司-precision-castparts" aria-label="Permalink to &quot;精密铸件公司（Precision Castparts）&quot;">​</a></h3><ul><li>2016年完成收购</li><li>2017年将贡献全年收益</li></ul><h3 id="金霸王-duracell" tabindex="-1">金霸王（Duracell） <a class="header-anchor" href="#金霸王-duracell" aria-label="Permalink to &quot;金霸王（Duracell）&quot;">​</a></h3><ul><li>2016年产生大量过渡性成本</li><li>2017年成本不会重现</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="连续14年承保盈利" tabindex="-1">连续14年承保盈利 <a class="header-anchor" href="#连续14年承保盈利" aria-label="Permalink to &quot;连续14年承保盈利&quot;">​</a></h3><ul><li>累计280亿美元税前收益</li><li>浮存金增至916亿美元</li><li>新签巨额保单使浮存金超过1000亿美元</li></ul><h2 id="五大业务表现" tabindex="-1">五大业务表现 <a class="header-anchor" href="#五大业务表现" aria-label="Permalink to &quot;五大业务表现&quot;">​</a></h2><h3 id="bnsf" tabindex="-1">BNSF <a class="header-anchor" href="#bnsf" aria-label="Permalink to &quot;BNSF&quot;">​</a></h3><ul><li>每吨英里收入约3美分</li><li>其他铁路4-5美分</li><li>利率覆盖率超过6:1</li></ul><h3 id="bhe" tabindex="-1">BHE <a class="header-anchor" href="#bhe" aria-label="Permalink to &quot;BHE&quot;">​</a></h3><ul><li>爱荷华州电价7.1美分/千瓦时（邻居9.0-10.0美分）</li><li>承诺2029年前不提高基本电价</li><li>风电占零售销售55%，2020年将达89%</li></ul><h3 id="clayton-homes" tabindex="-1">Clayton Homes <a class="header-anchor" href="#clayton-homes" aria-label="Permalink to &quot;Clayton Homes&quot;">​</a></h3><ul><li>成为美国最大房屋建筑商</li><li>交付42,075套住房，占全美新房5%</li><li>100%风险保留的抵押贷款实践</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><h3 id="主要持股" tabindex="-1">主要持股 <a class="header-anchor" href="#主要持股" aria-label="Permalink to &quot;主要持股&quot;">​</a></h3><ul><li>富国银行（10.0%）、可口可乐（9.3%）、IBM（8.5%）、美国运通（16.8%）</li><li>新增大额持仓：苹果（1.1%，67亿美元成本）</li></ul><h3 id="卡夫亨氏" tabindex="-1">卡夫亨氏 <a class="header-anchor" href="#卡夫亨氏" aria-label="Permalink to &quot;卡夫亨氏&quot;">​</a></h3><ul><li>持股3.25亿股</li><li>成本98亿美元</li><li>市值284亿美元（GAAP价值153亿美元）</li></ul><h3 id="美国银行" tabindex="-1">美国银行 <a class="header-anchor" href="#美国银行" aria-label="Permalink to &quot;美国银行&quot;">​</a></h3><ul><li>50亿美元优先股+认股权证</li><li>认股权证2021年9月到期</li><li>若股息升至44美分以上，将进行无现金转换</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="那场著名的赌局-2008-2017" tabindex="-1">那场著名的赌局（2008-2017） <a class="header-anchor" href="#那场著名的赌局-2008-2017" aria-label="Permalink to &quot;那场著名的赌局（2008-2017）&quot;">​</a></h3><ul><li>巴菲特赌标普500胜过五只对冲基金中的基金</li><li>九年结果：标普500年化7.1%，基金组合年化2.2%</li><li>100万美元投资：标普获85.4万收益，基金组合仅22万</li><li>费用&quot;吞噬&quot;了60%收益</li></ul><h3 id="对冲基金问题" tabindex="-1">对冲基金问题 <a class="header-anchor" href="#对冲基金问题" aria-label="Permalink to &quot;对冲基金问题&quot;">​</a></h3><ul><li>双重收费：底层基金费用+基金中的基金费用</li><li>&quot;2和20&quot;模式（2%管理费+20%业绩分成）</li><li>经理获得巨额报酬，投资者回报惨淡</li></ul><h3 id="投资成功三定律" tabindex="-1">投资成功三定律 <a class="header-anchor" href="#投资成功三定律" aria-label="Permalink to &quot;投资成功三定律&quot;">​</a></h3><ol><li>良好记录迅速吸引大量资金</li><li>巨额资金成为表现的锚</li><li>经理仍寻求新资金（个人利益驱动）</li></ol><h3 id="对投资者的建议" tabindex="-1">对投资者的建议 <a class="header-anchor" href="#对投资者的建议" aria-label="Permalink to &quot;对投资者的建议&quot;">​</a></h3><ul><li>低成本标普500指数基金</li><li>保持成本最低，长期持有</li><li>波动性不是风险，购买力损失才是</li></ul><h2 id="企业文化与管理" tabindex="-1">企业文化与管理 <a class="header-anchor" href="#企业文化与管理" aria-label="Permalink to &quot;企业文化与管理&quot;">​</a></h2><h3 id="管理层-调整后收益-的问题" tabindex="-1">管理层&quot;调整后收益&quot;的问题 <a class="header-anchor" href="#管理层-调整后收益-的问题" aria-label="Permalink to &quot;管理层&quot;调整后收益&quot;的问题&quot;">​</a></h3><ul><li>剔除&quot;重组成本&quot;和&quot;股权激励&quot;</li><li>这些是非常真实的成本</li><li>CEO应该接受：为什么这不是费用？或为什么收益计算要排除工资？</li></ul><h3 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h3><ul><li>固定资产折旧费用低估真实成本</li><li>铁路行业尤为突出</li><li>BNSF折旧费用远低于维持运营所需投资</li></ul><h2 id="生产力与繁荣" tabindex="-1">生产力与繁荣 <a class="header-anchor" href="#生产力与繁荣" aria-label="Permalink to &quot;生产力与繁荣&quot;">​</a></h2><h3 id="农业-1900-2016" tabindex="-1">农业（1900-2016） <a class="header-anchor" href="#农业-1900-2016" aria-label="Permalink to &quot;农业（1900-2016）&quot;">​</a></h3><ul><li>劳动力占比：40% → 2%</li><li>产量大幅增长</li><li>释放人力到其他领域</li></ul><h3 id="铁路-1947-2014" tabindex="-1">铁路（1947-2014） <a class="header-anchor" href="#铁路-1947-2014" aria-label="Permalink to &quot;铁路（1947-2014）&quot;">​</a></h3><ul><li>员工减少86%，货运量增长182%</li><li>实际运价下降55%</li><li>每年节省托运人约900亿美元</li></ul><h3 id="geico-1937-2016" tabindex="-1">GEICO（1937-2016） <a class="header-anchor" href="#geico-1937-2016" aria-label="Permalink to &quot;GEICO（1937-2016）&quot;">​</a></h3><ul><li>从年保费23.8万美元到226亿美元</li><li>承保费用占保费14.7%</li><li>低成本创造持久护城河</li></ul><h2 id="美国财富创造" tabindex="-1">美国财富创造 <a class="header-anchor" href="#美国财富创造" aria-label="Permalink to &quot;美国财富创造&quot;">​</a></h2><ul><li>240年间创造90万亿美元财富</li><li>外国人持有部分被美国海外资产抵消</li><li>市场体系出色配置资源</li><li>今天出生的婴儿是历史上最幸运的一代</li></ul><h2 id="重要风险" tabindex="-1">重要风险 <a class="header-anchor" href="#重要风险" aria-label="Permalink to &quot;重要风险&quot;">​</a></h2><h3 id="网络与大规模破坏性攻击" tabindex="-1">网络与大规模破坏性攻击 <a class="header-anchor" href="#网络与大规模破坏性攻击" aria-label="Permalink to &quot;网络与大规模破坏性攻击&quot;">​</a></h3><ul><li>对伯克希尔的重大威胁</li><li>短期小概率，长期接近确定</li><li>一年内三十分之一的概率 → 世纪内96.6%概率</li></ul><h2 id="企业文化特点" tabindex="-1">企业文化特点 <a class="header-anchor" href="#企业文化特点" aria-label="Permalink to &quot;企业文化特点&quot;">​</a></h2><ul><li>25人总部管理36万员工</li><li>&quot;虽然形式是公司，态度是合伙关系&quot;</li><li>管理者以所有者心态运营</li><li>薪酬与业绩挂钩</li></ul><h2 id="未来展望" tabindex="-1">未来展望 <a class="header-anchor" href="#未来展望" aria-label="Permalink to &quot;未来展望&quot;">​</a></h2><h3 id="遗嘱安排" tabindex="-1">遗嘱安排 <a class="header-anchor" href="#遗嘱安排" aria-label="Permalink to &quot;遗嘱安排&quot;">​</a></h3><ul><li>10%短期政府债券</li><li>90%低成本标普500指数基金</li><li>禁止投资其他地方</li></ul><h3 id="继任准备" tabindex="-1">继任准备 <a class="header-anchor" href="#继任准备" aria-label="Permalink to &quot;继任准备&quot;">​</a></h3><ul><li>CEO和投资经理已就位</li><li>文化将延续</li><li>霍华德·巴菲特作为非执行董事长确保传承</li></ul><h2 id="致华尔街" tabindex="-1">致华尔街 <a class="header-anchor" href="#致华尔街" aria-label="Permalink to &quot;致华尔街&quot;">​</a></h2><ul><li>伯克希尔乐意支付&quot;离谱费用&quot;给带来收购案的投行</li><li>为两位内部投资经理的卓越表现支付可观金额</li><li>当费用为伯克希尔创造价值时，欣然支付</li></ul>',72)])])}const b=l(t,[["render",o]]);export{q as __pageData,b as default};
